}
\end{eqnarray}

To express $kR,$ we multiply each entry of $R$ by $k,$ as follows:
\begin{align*}
k {R} &=
k\left\lbrack
\matrix {
-2 & 3 \\
0 & -1
}
\right\rbrack\\[5pt]
&=
\left\lbrack
\matrix {
-2k & 3k \\
0 & -k
}
\right\rbrack
\end{align*}
Now, we set the above result equal to the matrix given for $kR$ in the problem statement:
\[
\left\lbrack
\matrix {
-2k & 3k \\
0 & -k
}
\right\rbrack
=
\left\lbrack
\matrix {
2 & -3 \\
0 & 1
}
\right\rbrack.
\]
We can solve for $k$ by equating any two corresponding (nonzero) elements. Let's choose the top-right elements, $3k$ and $-3.$ Equating these elements, we get
\begin{align}
3k &= -3 \\[3pt]
k &= -1.
\end{align}
Note: We would still get the same result if we chose any other two corresponding (nonzero) elements.

We multiply each entry of $W$ by $-1$ and each entry of $A$ by $2,$ and then subtract the resulting matrices, as follows:
\[
\begin{align}
-{W} - 2{A}
&=
(-1)
\left\lbrack
\matrix {
-3 \\ 1 \\ 1
}
\right\rbrack
-
2
\left\lbrack
\matrix {
5 \\ -2 \\ 2
}
\right\rbrack \\[5pt]
&=
\left\lbrack
\matrix {
(-1) \cdot (-3) \\ (-1) \cdot 1 \\ (-1) \cdot 1
}
\right\rbrack
-
\left\lbrack
\matrix {
2 \cdot 5 \\ 2 \cdot (-2) \\ 2 \cdot 2
}
\right\rbrack \\[5pt]
&=
\left\lbrack
\matrix {
3 \\ -1 \\ -1
}
\right\rbrack
-
\left\lbrack
\matrix {
10 \\ -4 \\ 4
}
\right\rbrack \\[5pt]
&=
\left\lbrack
\matrix {
3-10 \\ -1-(-4) \\ -1-4
}
\right\rbrack \\[5pt]
&=
\left\lbrack
\matrix {
-7 \\ 3 \\ -5
}
\right\rbrack
\end{align}
\]

The operation $R_2 :=R_2 + 2 R_1$ means that we need to add $2$ times the first row to the second row.
Applying this row operation, we obtain the following:
\begin{align*}
T & =
\left[
\begin{array}{cc|c}
\color{blue}1 & \color{blue}3& \color{blue}2\\
-2 & -2& 1\\
\end{array}
\right] \qquad R_2 := R_2 + {\color{red}2} \cdot {\color{blue}R_1} \\[5pt]
&\sim
\left[
\begin{array}{cc|c}
\color{blue}1 & \color{blue}3 & \color{blue}2\\
-2 + ({\color{red}2})({\color{blue}1}) & -2 + ({\color{red}2})({\color{blue}3})& 1 + ({\color{red}2})({\color{blue}2})\\
\end{array}
\right] \\[5pt]
&\sim
\left[
\begin{array}{cc|c}
\color{blue}1 & \color{blue} 3& \color{blue}2\\
\color{red}0 & \color{red} 4& \color{red} 5\\
\end{array}
\right]
\end{align*}

The operation $R_2:=R_2 + (-3)\cdot R_1$ means that we need to add $-3$ times the first row to the second row.
Applying this row operation, we obtain the following:
\begin{align*}
B & =
\left[
\begin{array}{cc|c}
\color{blue}1 & \color{blue}-1& \color{blue}2\\
3 & -4& 4\\
\end{array}
\right] \qquad R_2 := R_2 + ({\color{red}-3}) \cdot {\color{blue}R_1} \\[5pt]
&\sim
\left[
\begin{array}{cc|c}
\color{blue}1 & \color{blue}-1 & \color{blue}2\\
3+ ({\color{red}-3})({\color{blue}1}) & -4+ ({\color{red}-3})({\color{blue}-1})& 4+ ({\color{red}-3})({\color{blue}2})\\
\end{array}
\right] \\[5pt]
&\sim
\left[
\begin{array}{cc|c}
\color{blue}1 & \color{blue}-1 & \color{blue}2\\
\color{red}0 & \color{red}-1& \color{red}-2\\
\end{array}
\right]
\end{align*}

First, we isolate the $\sqrt{x}$ term by subtracting $3$ from both sides
\begin{align}
\sqrt{x}+3 & = 10\\[5pt]
\sqrt{x} & = 7
\end{align}
Squaring both sides of the equation, we get
\begin{align}
\sqrt{x} & = 7\\[3pt]
(\sqrt{x})^2 & = 7^2\\[3pt]
x & = 49.
\end{align}
Let's check the result by plugging it into the original equation:
\begin{align}
\sqrt{49}+3 & \overset{?}{=} 10\\[5pt]
7+3 & \overset{?}{=} 10\\[5pt]
10 & = 10\;\; {\color{green}\checkmark}
\end{align}
The value $x = 49$ satisfies the original equation, so we can accept it as a solution.
Therefore, the solution to $\sqrt{x}+3=10$ is $x = 49.$

We can collapse the given expression using product notation over the index $t$ from $t = 2$ to $t = p{:}$
\begin{align*}
\dfrac{2 \cdot \bbox[Gainsboro,2pt]{2} }{3 \cdot \bbox[Gainsboro,2pt]{2} + 1} \cdot
\dfrac{2 \cdot \bbox[Gainsboro,2pt]{3} }{3 \cdot \bbox[Gainsboro,2pt]{3} + 1} \cdot
\dfrac{2 \cdot \bbox[Gainsboro,2pt]{4} }{3 \cdot \bbox[Gainsboro,2pt]{4} + 1} \cdot
\: \ldots \: \cdot
\dfrac{2 \bbox[Gainsboro,2pt]{p} }{3 \bbox[Gainsboro,2pt]{p} + 1}
= \prod_{t = 2}^{p} \dfrac{2\bbox[Gainsboro,2pt]{t}}{3\bbox[Gainsboro,2pt]{t} + 1}
\end{align*}

We add the corresponding entries:
\begin{align*}
M + N &=
\left\lbrack
\matrix {
3 & -6 & 14 \\
2 & 9 & -13
}
\right\rbrack
+
\left\lbrack
\matrix {
-15 & -6 & -13 \\
-1 & -8 & 14
}
\right\rbrack \\[5pt]
&=
\left\lbrack
\matrix {
3 + (-15) & -6 + (-6) & 14 + (-13) \\
2 + (-1) & 9 + (-8) & -13 + 14
}
\right\rbrack\\[5pt]
&=
\left\lbrack
\matrix {
-12 & -12 & 1 \\
1 & 1 & 1
}
\right\rbrack
\end{align*}

Squaring both sides of the equation, we get
\begin{align}
\sqrt{3q^2 - 5q + 14} & = 4\\[5pt]
\left( \sqrt{3q^2 - 5q + 14} \right)^2 & = 4^2\\[5pt]
3q^2 - 5q + 14 & = 16\\[5pt]
3q^2 - 5q - 2 & = 0\\[5pt]
(3q + 1)(q - 2) & = 0\\[5pt]
q & = -\dfrac{1}{3}, \, 2.
\end{align}
Let's check the result by plugging the solutions into the original equation.
For $q = -\dfrac{1}{3},$ we get
\begin{align}
\sqrt{3\left(-\dfrac{1}{3}\right)^2 - 5\left(-\dfrac{1}{3}\right) + 14} & \overset{?}{=} 4\\[5pt]
\sqrt{\dfrac{1}{3} + \dfrac{5}{3} + 14} & \overset{?}{=} 4\\[5pt]
\sqrt{16} &\overset{?}{=} 4\\[5pt]
4 & = 4\;\; {\color{green}\checkmark}
\end{align}
For $q = 2,$ we get
\begin{align}
\sqrt{3(2^2) - 5(2) + 14} & \overset{?}{=} 4\\[5pt]
\sqrt{12 - 10 + 14} &\overset{?}{=} 4\\[5pt]
\sqrt{16} &\overset{?}{=} 4\\[5pt]
4 & = 4\;\; {\color{green}\checkmark}
\end{align}
The values $q = -\dfrac{1}{3}, \, 2$ satisfy the original equation, so we can accept them as solutions.
Therefore, the solutions to $\sqrt{3q^2 - 5q + 14} = 4$ are $q = -\dfrac{1}{3}$ and $q = 2.$

