questions.explanation_text:
We subtract the corresponding entries:
\[
\begin{align}
{R}- {S}
&=
\left\lbrack
\matrix {
7 & 5 \\
5 & 4
}
\right\rbrack
-
\left\lbrack
\matrix {
3 & 2 \\
-1 & 0
}
\right\rbrack \\[5pt]
&=
\left\lbrack
\matrix {
7 - 3 & 5 - 2 \\
5 - (-1) & 4 - 0
}
\right\rbrack \\[5pt]
&=
\left\lbrack
\matrix {
4 & 3 \\
6 & 4
}
\right\rbrack
\end{align}
\]

We use the change of base formula:
\[
\log_a X = \dfrac {\log_b X} {\log_b a}
\]
We want to change from base $a=81$ to base $b=3.$ So, we have
\begin{align}
\log_{81} x
& = \dfrac {\log_{3} x} {\log_{3} (81)} .
\end{align}
Rewriting the expression in the denominator using exponents, we get
\begin{align}
\dfrac {\log_3 x} {\log_3 (81)}
&=\dfrac {\log_3 x} {\log_3 (3^4)}\\[5pt]
&=\dfrac {\log_3 x} {4}.
\end{align}
Therefore, we conclude that
\[
\log_{81}x = \dfrac {\log_3 x} {4} = \dfrac{1}{4}\log_3 x .
\]

Let $g(x)=3x+4$ and $f(g(x)) = g(x)^{5}.$
Differentiating, we have
\begin{align*}
f'(g(x)) & = ( g^{5})' = 5g^{4}, \\[5pt]
g'(x) & = (3x + 4)' = 3.
\end{align*}
Then, using the chain rule,
\begin{align*}
f'(x) & = f'(g(x))\cdot g'(x)\\[5pt]
& = 5g^{4} \cdot 3\\[5pt]
& = 15(3x + 4)^4.
\end{align*}

Let $g(x)=x - x^2$ and $f(g(x)) = -\dfrac{4}{\sqrt{g}} = -4g^{-1/2}.$
Differentiating, we have
\begin{align*}
f'(g(x)) & = -4( g^{-1/2})' = 4\cdot \dfrac{1}{2} g^{-3/2} = \dfrac 2{g^{3/2}} , \\[5pt]
g'(x) & = (x - x^2)' = 1 - 2x.
\end{align*}
Then, using the chain rule,
\begin{align*}
f'(x) & = f'(g(x))\cdot g'(x)\\[3pt]
& = \dfrac{2}{g^{3/2}} \cdot (1 - 2x)\\[3pt]
% & = \dfrac{2 - 4x}{g^{3/2} } \\[3pt]
& = \dfrac{2 - 4x}{\sqrt{(x - x^2)^3} }.
\end{align*}

The derivative of $e^x$ is just $e^x$ itself. On the other hand, $4$ and $-\ln{6}$ are constants, so their derivatives are $0.$
Using the addition rule, then, we have
\begin{eqnarray}
\eqalign{
f'(x) & = \dfrac{\textrm{d}}{\textrm{d}x} \left(4-3e^x-\ln 6\right) \\[5pt]
& =\dfrac{\textrm{d}}{\textrm{d}x}(4)+\dfrac{\textrm{d}}{\textrm{d}x}(-3e^x)+ \dfrac{\textrm{d}}{\textrm{d}x}(-\ln{6}) \\[5pt]
& =0-3\dfrac{\textrm{d}}{\textrm{d}x}(e^x)+0\\[5pt]
& = -3e^x.
}
\end{eqnarray}

Applying the formula, we get
\begin{eqnarray}
\eqalign{
f'(x)&=\dfrac {\textrm{d}} {\textrm{d}x} \left(-4^{x} + 7e^x\right)\\[5pt]
&=\dfrac {\textrm{d}} {\textrm{d}x} \left(-4^{x}\right)+\dfrac {\textrm{d}} {\textrm{d}x} \left(7e^x\right)\\[5pt]
&=\dfrac {\textrm{d}} {\textrm{d}x} \left(-4^{x}\right)+7\dfrac {\textrm{d}} {\textrm{d}x} \left(e^x\right)\\[5pt]
& = -4^x \cdot \ln 4 + 7e^x \\[5pt]
& = -4^x\ \ln 4 + 7e^x.
}
\end{eqnarray}

Applying the formula, we get
\begin{align*}
f'(x)&= \dfrac{\textrm d}{\textrm d x}\left(3\cdot 2^x-3x^4-4\right)\\[5pt]
&= \dfrac{\textrm d}{\textrm d x}\left(3\cdot 2^x\right)-\dfrac{\textrm d}{\textrm d x}\left(3x^4\right)-\dfrac{\textrm d}{\textrm d x}\left(4\right)\\[5pt]
&= 3\dfrac{\textrm d}{\textrm d x}\left(2^x\right)-3\dfrac{\textrm d}{\textrm d x}\left(x^4\right)-\dfrac{\textrm d}{\textrm d x}\left(4\right)\\[5pt]
&=3 \ln 2 \cdot 2^{x} - 3 \cdot 4x^3-0\\[5pt]
&=3 \ln 2 \cdot 2^{x}-12x^3.
\end{align*}
Therefore, the slope at $x=0$ is
\begin{align*}
\left.\dfrac {\textrm{d}f} {\textrm{d}x}\right|_{x=0}
&=\left.\left( 3 \ln 2 \cdot 2^{x}-12x^3\right)\right|_{x=0}\\[5pt]
&=3 \ln 2 \cdot 2^{0}-12(0)^3\\[5pt]
&=3 \ln 2.
\end{align*}

Let $f(x)=\dfrac{2}{x^5}+7x.$ Computing the derivative $f'(x)$ gives
\begin{align*}
f'(x) & = \dfrac {\textrm{d}}{\textrm{d}x} \left(\dfrac{2}{x^5} + 7x\right) \\
& = \dfrac {\textrm{d}}{\textrm{d}x} \left(2x^{-5} + 7x\right) \\
&= -10x^{-6} + 7.
\end{align*}
We then compute $f'(1)$, which gives
\begin{align*}
f'(1) = -10(1)^{-6} + 7 = -3.
\end{align*}
Finally, we use the point-slope form with $m=-3$ and the coordinates of our point $(1,9),$ and get
\begin{align*}
y - y_1 &= m(x-x_1) \\
y - (9) &= -3(x-1) \\
y & =-3x + 3 +9\\
y & =-3x + 12.
\end{align*}

Let $f(x)=x^2+5x.$ Computing the derivative $f'(x)$ gives
\begin{align*}
f'(x) = \dfrac {\textrm{d}}{\textrm{d}x} \left(x^2 + 5x\right)= 2x+5.
\end{align*}
We then compute $f'(-1)$, which gives
\begin{align*}
f'(-1) = 2(-1)+5 = 3 \,.
\end{align*}
Finally, we use the point-slope form with $m=3$ and the coordinates of our point $(-1, -4),$ and get
\begin{align*}
y - y_1 &= m(x-x_1) \\
y - (-4) &= 3(x-(-1)) \\
y +4 &= 3(x+1) \\
y & = 3x +3 -4\\
y &= 3x-1.
\end{align*}

Let $f(x)=x^2-3x.$ Computing the derivative $f'(x)$ gives
\begin{align*}
f'(x) = \dfrac {\textrm{d}}{\textrm{d}x} \left(x^2 - 3x\right)= 2x-3.
\end{align*}
We then compute $f'(-2)$, which gives
\begin{align*}
f'(-2) = 2(-2)-3 = -7.
\end{align*}
Finally, we use the point-slope form with $m=-7$ and the coordinates of our point $(-2, 10),$ and get
\begin{align*}
y - y_1 &= m(x-x_1) \\
y - (10) &= -7(x-(-2)) \\
y - 10 &= -7(x+2) \\
y & = -7x - 14 +10\\
y &= -7x -4.
\end{align*}
